//! Generate OpenAPI YAML for the Additional Properties API (multi-level HashMaps).

use clap::Parser;
use std::path::PathBuf;
use utoipa::OpenApi;

use fixture_generator_additional_properties::ApiDoc;

const GENERATED_FILE_HEADER_YAML: &str = r#"# DO NOT EDIT - This file is automatically generated.
# Any manual changes will be overwritten on the next generation.
# To make changes, modify the source code and regenerate this file.

"#;

#[derive(Parser)]
#[command(about = "Generate OpenAPI YAML for the Additional Properties API")]
struct Args {
    /// Output directory for generated files
    #[arg(
        short,
        long,
        default_value = "tests/fixtures/valid/additional-properties"
    )]
    output_dir: PathBuf,
}

fn main() {
    let args = Args::parse();

    let openapi = ApiDoc::openapi();

    let yaml = openapi
        .to_yaml()
        .expect("Failed to serialize OpenAPI spec to YAML");
    let yaml_with_header = format!("{}{}", GENERATED_FILE_HEADER_YAML, yaml);

    std::fs::create_dir_all(&args.output_dir).expect("Failed to create output directory");

    let yaml_path = args.output_dir.join("additional-properties.yaml");
    std::fs::write(&yaml_path, yaml_with_header)
        .expect("Failed to write OpenAPI spec to YAML file");

    println!("✅ OpenAPI specification generated:");
    println!("   📄 YAML: {}", yaml_path.display());
}
